For each order, try inserting into all existing assigns and empty slots, scoring by weighted sum of cost increase and load efficiency penalty, preferring minimal positive delta with load balancing, falling back to first available empty slot, ensuring every order is assigned and renewing total cost once.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		idx     int
		score   float64
		costDelta float64
		loadPenalty float64
	}
	const loadWeight = 0.3
	const capacityThreshold = 10
	for jj := range oris {
		shipID := total_ship + jj
		best := candidate{-1, 1e18, 0.0, 0.0}
		savedCosts := make([]float64, dispatch.AssignsLen)
		savedLens := make([]int, dispatch.AssignsLen)
		savedCurrents := make([]Station, dispatch.AssignsLen)
		for i := 0; i < dispatch.AssignsLen; i++ {
			savedCosts[i] = dispatch.Assigns[i].Cost
			savedLens[i] = dispatch.Assigns[i].StationsLen
			savedCurrents[i] = dispatch.Assigns[i].StationCurrent
		}
		hasNonEmpty := false
		for i := 0; i < dispatch.AssignsLen; i++ {
			if dispatch.Assigns[i].StationsLen > 0 {
				hasNonEmpty = true
				break
			}
		}
		if hasNonEmpty {
			for i := 0; i < dispatch.AssignsLen; i++ {
				assign := &dispatch.Assigns[i]
				if assign.StationsLen == 0 {
					continue
				}
				ok := assign.AddShip(shipID, oris[jj], dess[jj])
				if !ok {
					continue
				}
				assign.GenRoute()
				if assign.Cost < 0 {
					assign.RemoveShip(shipID)
					assign.Cost = savedCosts[i]
					assign.StationsLen = savedLens[i]
					assign.StationCurrent = savedCurrents[i]
					if savedLens[i] > 0 {
						assign.GenRoute()
					}
					continue
				}
				delta := assign.Cost - savedCosts[i]
				currentLoad := 0
				if assign.StationsLen > 0 {
					for k := 0; k < assign.StationsLen; k++ {
						if assign.Stations[k].ReqCode == 1 {
							currentLoad += assign.Stations[k].Load
						} else if assign.Stations[k].ReqCode == 2 {
							currentLoad -= assign.Stations[k].Load
						}
					}
				}
				loadPenalty := 0.0
				if currentLoad > capacityThreshold {
					loadPenalty = float64(currentLoad-capacityThreshold) * loadWeight
				}
				score := delta + loadPenalty
				if score < best.score && delta >= 0 {
					best.idx = i
					best.score = score
					best.costDelta = delta
					best.loadPenalty = loadPenalty
				}
				assign.RemoveShip(shipID)
				assign.Cost = savedCosts[i]
				assign.StationsLen = savedLens[i]
				assign.StationCurrent = savedCurrents[i]
				if savedLens[i] > 0 {
					assign.GenRoute()
				}
			}
		}
		if best.idx != -1 {
			chosen := &dispatch.Assigns[best.idx]
			chosen.AddShip(shipID, oris[jj], dess[jj])
			chosen.GenRoute()
		} else {
			inserted := false
			for i := 0; i < MAXASSIGNS; i++ {
				var target *Assign
				slotIdx := -1
				if i < dispatch.AssignsLen {
					target = &dispatch.Assigns[i]
					if target.StationsLen > 0 {
						continue
					}
					slotIdx = i
				} else {
					if i >= MAXASSIGNS {
						break
					}
					target = &dispatch.Assigns[i]
					slotIdx = i
				}
				ok := target.AddShip(shipID, oris[jj], dess[jj])
				if !ok {
					continue
				}
				target.GenRoute()
				if target.Cost >= 0 {
					if slotIdx >= dispatch.AssignsLen {
						dispatch.AssignsLen = slotIdx + 1
					}
					inserted = true
					break
				} else {
					target.RemoveShip(shipID)
					target.GenRoute()
				}
			}
			if !inserted {
				firstEmpty := -1
				for i := 0; i < MAXASSIGNS; i++ {
					if i < dispatch.AssignsLen && dispatch.Assigns[i].StationsLen == 0 {
						firstEmpty = i
						break
					}
					if i >= dispatch.AssignsLen && i < MAXASSIGNS {
						firstEmpty = i
						break
					}
				}
				if firstEmpty >= 0 && firstEmpty < MAXASSIGNS {
					target := &dispatch.Assigns[firstEmpty]
					ok := target.AddShip(shipID, oris[jj], dess[jj])
					if ok {
						target.GenRoute()
						if firstEmpty >= dispatch.AssignsLen {
							dispatch.AssignsLen = firstEmpty + 1
						}
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

